// Validate input from seeder
const body = $input.first().json;
const slug = (body.slug || '').trim().toLowerCase();
const name = (body.name || '').trim();
const category = (body.category || 'Integration').trim();
const pluginId = (body.plugin_id || '').trim();
const credType = (body.credential_type || 'OAuth 2.0').trim();
const minVersion = (body.min_version || 'Rome').trim();

if (!slug || !name) {
  return [{ json: { valid: false, error: 'slug and name required' } }];
}

return [{ json: { valid: true, slug, name, category, pluginId, credType, minVersion } }];

