// Parse the OpenRouter response and extract JSON
const response = $input.first().json;
const slug = $('Validate Input').first().json.slug;

// Check for API errors
if (response.error) {
  return [{ json: { success: false, error: response.error.message || 'OpenRouter error', slug } }];
}

const content = response?.choices?.[0]?.message?.content || '';
if (!content) {
  return [{ json: { success: false, error: 'Empty AI response', slug } }];
}

// Parse JSON from response
let spokeData;
try {
  // Strip markdown code blocks if present
  const cleaned = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const match = cleaned.match(/\{[\s\S]*\}/);
  spokeData = JSON.parse(match ? match[0] : cleaned);
} catch (parseErr) {
  return [{ json: { success: false, error: 'JSON parse failed: ' + parseErr.message, raw: content.substring(0, 200), slug } }];
}

// Validate required fields
if (!spokeData.actions || !Array.isArray(spokeData.actions) || spokeData.actions.length === 0) {
  return [{ json: { success: false, error: 'No actions generated', slug } }];
}

return [{ json: { success: true, slug, spoke: spokeData, model: response.model } }];

const dbResult = $input.first().json;
const spokeName = $('Parse AI Response').first().json.spoke?.name || '';
return [{ json: { success: true, message: 'Spoke enriched successfully', name: spokeName, slug: $('Parse AI Response').first().json.slug } }];

const err = $json.error || 'Parse failed';
const slug = $json.slug || 'unknown';
return [{ json: { success: false, error: err, slug } }];
